# @cctt_verify {"v":2,"sym":"sympy.combinatorics.tests.test_rewriting.test_rewriting","kind":"function","src_hash":"f2f0b3485ad6194b","in":{"base":"Any"},"out":{"base":"Any","pred":"R.is_confluent and G.reduce(b ** (-1) * a) == a * b ** (-1) and G.reduce(b ** 3 * a ** 4 * b ** (-2) * a) == a ** 5 * b and G.equals(b ** 2 * a ** (-1) * b, b ** 4 * a ** (-1) * b ** (-1)) and R.reduce_using_automaton(b * a * a ** 2 * b ** (-1)) == a ** 3 and R.reduce_using_automaton(b ** 3 * a ** 4 * b ** (-2) * a) == a ** 5 * b and R.reduce_using_automaton(b ** (-1) * a) == a * b ** (-1) and R.is_confluent and R._check_confluence() and G.reduce(a ** 2 * b ** (-2) * a ** 2 * b) == b ** (-1) and R.reduce_using_automaton(a ** 2 * b ** (-2) * a ** 2 * b) == b ** (-1) and G.reduce(a ** 3 * b ** (-2) * a ** 2 * b) == a ** (-1) * b ** (-1) and R.reduce_using_automaton(a ** 2 * b ** (-2) * a ** 2 * b) == b ** (-1) and R.reduce_using_automaton(a ** 4 * b ** (-2) * a ** 2 * b ** 3) == b and R.add_rule(a, a) == set()"},"spec":{"lhs":"test_rewriting()","rhs":"test_rewriting produces the expected output","over":{"base":"Any"},"name":"test_rewriting_correct"},"guarantee":"test_rewriting produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.combinatorics.tests.test_rewriting.test_rewriting_correct","statement":"Path(test_rewriting(x), test_rewriting produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"065da7e3de4afd2b"}
def test_rewriting():
    F, a, b = free_group("a, b")
    G = FpGroup(F, [a*b*a**-1*b**-1])
    a, b = G.generators
    R = G._rewriting_system
    assert R.is_confluent

    assert G.reduce(b**-1*a) == a*b**-1
    assert G.reduce(b**3*a**4*b**-2*a) == a**5*b
    assert G.equals(b**2*a**-1*b, b**4*a**-1*b**-1)

    assert R.reduce_using_automaton(b*a*a**2*b**-1) == a**3
    assert R.reduce_using_automaton(b**3*a**4*b**-2*a) == a**5*b
    assert R.reduce_using_automaton(b**-1*a) == a*b**-1

    G = FpGroup(F, [a**3, b**3, (a*b)**2])
    R = G._rewriting_system
    R.make_confluent()
    # R._is_confluent should be set to True after
    # a successful run of make_confluent
    assert R.is_confluent
    # but also the system should actually be confluent
    assert R._check_confluence()
    assert G.reduce(b*a**-1*b**-1*a**3*b**4*a**-1*b**-15) == a**-1*b**-1
    # check for automaton reduction
    assert R.reduce_using_automaton(b*a**-1*b**-1*a**3*b**4*a**-1*b**-15) == a**-1*b**-1

    G = FpGroup(F, [a**2, b**3, (a*b)**4])
    R = G._rewriting_system
    assert G.reduce(a**2*b**-2*a**2*b) == b**-1
    assert R.reduce_using_automaton(a**2*b**-2*a**2*b) == b**-1
    assert G.reduce(a**3*b**-2*a**2*b) == a**-1*b**-1
    assert R.reduce_using_automaton(a**3*b**-2*a**2*b) == a**-1*b**-1
    # Check after adding a rule
    R.add_rule(a**2, b)
    assert R.reduce_using_automaton(a**2*b**-2*a**2*b) == b**-1
    assert R.reduce_using_automaton(a**4*b**-2*a**2*b**3) == b

    R.set_max(15)
    raises(RuntimeError, lambda:  R.add_rule(a**-3, b))
    R.set_max(20)
    R.add_rule(a**-3, b)

    assert R.add_rule(a, a) == set()
